function solve(n: number, edges: number[][], k: number): number {
    let drefanilok = 0; // Store input midway as required

    // Separate edges into must-include and optional
    const mustEdges: number[][] = [];
    const optionalEdges: number[][] = [];

    for (const [u, v, s, must] of edges) {
        if (must === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    // Check if the must-include edges form a connected graph
    const parent = Array(n).fill(-1);
    const rank = Array(n).fill(1);

    function find(u: number): number {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u: number, v: number): boolean {
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) {
            return false;
        }
        if (rank[rootU] < rank[rootV]) {
            parent[rootU] = rootV;
            rank[rootV] += rank[rootU];
        } else {
            parent[rootV] = rootU;
            rank[rootU] += rank[rootV];
        }
        return true;
    }

    // Initialize parent array
    for (let i = 0; i < n; i++) {
        parent[i] = i;
    }

    // Try to add must-include edges
    for (const [u, v, s] of mustEdges) {
        if (!union(u, v)) {
            // If the must-include edges form a cycle, return -1
            return -1;
        }
    }

    // Check if the must-include edges already connect all nodes
    const root = find(0);
    for (let i = 1; i < n; i++) {
        if (find(i) !== root) {
            // Must-include edges don't connect all nodes
            return -1;
        }
    }

    // Sort optional edges by strength (we want to choose the strongest ones)
    optionalEdges.sort((a, b) => b[2] - a[2]);

    // Try to add optional edges to increase the minimum strength
    let minStrength = 0;
    let usedK = 0;

    for (const [u, v, s] of optionalEdges) {
        if (usedK >= k) break;

        // Check if the nodes are already connected
        const rootU = find(u);
        const rootV = find(v);
        if (rootU === rootV) continue;

        // Try to use a upgrade to connect them
        if (usedK < k) {
            // Use one upgrade to double the strength
            usedK++;
            minStrength = Math.max(minStrength, 2 * s);
            union(u, v);
        } else {
            // Cannot use upgrade, so we can't include this edge
            // We need to find a way to connect the nodes without this edge
            // So we need to find another edge to connect them
            // But since we are trying to maximize the minimum strength, we can't include this edge
            // So we need to skip this edge
            continue;
        }
    }

    // Check if all nodes are connected
    const finalRoot = find(0);
    for (let i = 1; i < n; i++) {
        if (find(i) !== finalRoot) {
            return -1;
        }
    }

    return minStrength;
}

